import time
from dataclasses import dataclass
from typing import Dict, List, Optional, Tuple, Union
from lightllm.server.core.objs import ShmReqManager, Req
from lightllm.utils.log_utils import init_logger
from .stats import RouterStatics

logger = init_logger(__name__)


class Batch:
    def __init__(self, batch_id, reqs: List[Req], dp_size_in_node: int):
        self.batch_id = batch_id
        self.reqs = reqs
        self.id_to_reqs = {req.request_id: req for req in reqs}
        self.dp_size_in_node = dp_size_in_node
        return

    def input_tokens(self):
        batch_input_tokens = 0
        for req in self.reqs:
            batch_input_tokens += req.input_len
        return batch_input_tokens

    def get_batch_decode_need_tokens(self):
        new_batch_decode_need_tokens = [0 for _ in range(self.dp_size_in_node)]  # for chunked prefill

        for req in self.reqs:
            req_dp_index = req.sample_params.suggested_dp_index
            new_batch_decode_need_tokens[req_dp_index] += req.get_decode_need_tokens()

        return new_batch_decode_need_tokens

    def get_req_list_for_dp(self, dp_index: int):
        if self.dp_size_in_node == 1:
            return self.reqs

        req_list = []
        for req in self.reqs:
            if req.sample_params.suggested_dp_index == dp_index:
                req_list.append(req)
        return req_list

    def get_all_dp_req_num(self) -> List[int]:
        if self.dp_size_in_node == 1:
            return [len(self.reqs)]

        all_dp_req_num = [0 for _ in range(self.dp_size_in_node)]
        for req in self.reqs:
            all_dp_req_num[req.sample_params.suggested_dp_index] += 1
        return all_dp_req_num

    def filter_out_finished_req(self, shm_req_manager: ShmReqManager, router_statics: RouterStatics):
        unfinished_req_ids = []
        for req in self.reqs:
            if req.shm_infer_released:
                logger.info(f"router release req id {req.request_id}")
                if not req.is_aborted:
                    router_statics.update(req.candetoken_out_len)

                shm_req_manager.put_back_req_obj(req)
                req = None
            else:
                unfinished_req_ids.append(req.request_id)

        self.reqs = [self.id_to_reqs[req_id] for req_id in unfinished_req_ids]
        self.id_to_reqs = {req.request_id: req for req in self.reqs}
        return

    def pop_req(self, req_id) -> Req:
        self.reqs = [req for req in self.reqs if req.request_id != req_id]
        req = self.id_to_reqs.pop(req_id)
        return req

    def is_clear(self):
        return len(self.reqs) == 0

    def merge(self, mini_batch: "Batch"):
        if mini_batch is None:
            return

        for _req in mini_batch.reqs:
            self.reqs.append(_req)
        self.id_to_reqs = {req.request_id: req for req in self.reqs}
        return

    @staticmethod
    def merge_two_batch(batch1: "Batch", batch2: "Batch") -> "Batch":
        if batch1 is None and batch2 is None:
            return None

        not_none_batch = batch1 if batch1 is not None else batch2

        merge_batch = Batch(-1, [], not_none_batch.dp_size_in_node)
        merge_batch.merge(batch1)
        merge_batch.merge(batch2)
        return merge_batch

    def __repr__(self):
        return f"batch_id={self.batch_id}, " f"reqs={self.reqs}, "

    def simple_log(self):
        details_tuples = [(req.request_id, req.index_in_shm_mem) for req in self.reqs]
        return f"batch_id={self.batch_id}, time:{time.time()}s (req_id, shm_index)s:{details_tuples}"

from typing import List, Dict
from lightllm.utils.infer_utils import calculate_time
from ..batch import Batch, Req
from lightllm.server.core.objs import FinishStatus
from lightllm.utils.config_utils import get_fixed_kv_len
from lightllm.server.core.objs import StartArgs


class BaseQueue:
    def __init__(self, args: StartArgs, router, dp_index, dp_size_in_node) -> None:
        self.args = args
        self.dp_index = dp_index
        self.dp_size_in_node = dp_size_in_node
        from lightllm.server.router.manager import RouterManager

        self.router: RouterManager = router
        # max_total_token_num - get_fixed_kv_len() 是为了减去被特定
        # 推理模式预先占用了部分token kv 资源，这会导致整体可用的kv 资源
        # 在极端情况下减少，在非特定模式下，get_fixed_kv_len() 返回的都是
        # 0， 不会有任何影响。
        self.max_total_tokens = args.max_total_token_num - get_fixed_kv_len()
        assert args.batch_max_tokens is not None
        self.batch_max_tokens = args.batch_max_tokens
        self.running_max_req_size = args.running_max_req_size  # Maximum number of concurrent requests
        self.waiting_req_list: List[Req] = []  # List of queued requests
        self.router_token_ratio = args.router_token_ratio  # ratio to determine whether the router is busy

    def free_aborted_req_cpu_cache_pages(self, req: Req):
        if self.args.enable_cpu_cache:
            self.router.cpu_cache_client.lock.acquire_sleep1ms()
            self.router.cpu_cache_client.deref_pages(req.cpu_cache_match_page_indexes.get_all())
            req.cpu_cache_match_page_indexes.clear()
            self.router.cpu_cache_client.lock.release()

    def extend(self, req_group: List[Req]):
        for req in req_group:
            req.sample_params.suggested_dp_index = self.dp_index
        self.waiting_req_list.extend(req_group)
        return

    def get_wait_req_num(self):
        return len(self.waiting_req_list)

    def is_busy(self):
        # 计算当前所有的token使用量, 如果使用了dynamic prompt cache, 使用的token量中不包含，cache tree 中未被引用的数据。
        cur_all_used_tokens = self.router.get_used_tokens(self.dp_index)
        # 判断当前服务是否处于token使用率过高的状态，过高的情况下，调度要偏向保守
        cur_token_ratio = cur_all_used_tokens / self.max_total_tokens
        is_busy = cur_token_ratio >= self.router_token_ratio
        return is_busy

    def get_batch_dp_req_size(self, current_batch: Batch):
        if current_batch is None:
            return 0
        if self.dp_size_in_node == 1:
            return len(current_batch.reqs)

        return len([req for req in current_batch.reqs if req.sample_params.suggested_dp_index == self.dp_index])

    def generate_new_batch(self, current_batch: Batch):
        """
        args:
            current_batch: current batch
        return:
            new batch
        """
        raise NotImplementedError()

    def calcu_batch_token_load(self, current_batch: Batch):
        if current_batch is None:
            return 0, 0.0
        else:
            return self._calcu_batch_token_load_batch_not_none(current_batch)

    def _calcu_batch_token_load_batch_not_none(self, current_batch: Batch):
        raise NotImplementedError()

    def update_token_load(self, current_batch: Batch, force_update=False):
        if self.router.shared_token_load.need_update_dynamic_max_load() or force_update:
            estimated_peak_token_count, dynamic_max_load = self.calcu_batch_token_load(current_batch)
            token_ratio1 = self.router.get_used_tokens(self.dp_index) / self.router.max_total_token_num
            self.router.shared_token_load.set_current_load(token_ratio1, self.dp_index)
            self.router.shared_token_load.set_estimated_peak_token_count(estimated_peak_token_count, self.dp_index)
            self.router.shared_token_load.set_dynamic_max_load(dynamic_max_load, self.dp_index)
        return

from .chunked_prefill.impl import ChunkedPrefillQueue
from .chunked_prefill.beam_impl import ChunkedBeamContinuesBatchQueue
from .chunked_prefill.impl_for_pd import PDQueue
from .dp_base_queue import DpQueue


def _get_req_queue_class(args, router, dp_size_in_node: int):
    if args.diverse_mode:
        return ChunkedBeamContinuesBatchQueue
    if args.token_healing_mode:
        return ChunkedPrefillQueue
    if args.output_constraint_mode != "none":
        return ChunkedPrefillQueue
    if args.first_token_constraint_mode:
        return ChunkedPrefillQueue
    if args.run_mode in ["prefill", "decode"]:
        return PDQueue

    if args.disable_chunked_prefill:
        # 虽然也使用chuncked prefill queue 但是由于 args.chunked_prefill_size = args.max_req_total_len
        # 所以调度的实际行为类似过去的 continues batch 调度，所以将两种调度的实现统一为一种实现，减少代码重复。
        return ChunkedPrefillQueue
    else:
        return ChunkedPrefillQueue


def build_req_queue(args, router, dp_size_in_node: int):
    queue_class = _get_req_queue_class(args, router, dp_size_in_node)

    if dp_size_in_node == 1:
        return queue_class(args, router, 0, dp_size_in_node)
    else:
        return DpQueue(args, router, queue_class, dp_size_in_node)
